UPDATE checkin_questions SET label = 'I dried my grain to safe moisture',          description = 'I dried my grain to 13% moisture content or below before storage.'                                  WHERE organisation_id = org_id AND crop_type = 'maize' AND week_number = 12 AND label ILIKE '%dried%';
UPDATE checkin_questions SET label = 'I stored my grain properly',                 description = 'I stored my grain in a clean, pest-free facility or hermetic bag.'                                  WHERE organisation_id = org_id AND crop_type = 'maize' AND week_number = 12 AND label ILIKE '%stored%';
UPDATE checkin_questions SET label = 'I used climate-smart storage',               description = 'I used hermetic storage or metal silos to protect my grain from post-harvest losses.'               WHERE organisation_id = org_id AND crop_type = 'maize' AND week_number = 12 AND label ILIKE '%storage method%';
UPDATE checkin_questions SET label = 'I completed the post-harvest debrief',       description = 'I attended or participated in the post-season debrief session.'                                     WHERE organisation_id = org_id AND crop_type = 'maize' AND week_number = 12 AND label ILIKE '%debrief%';
UPDATE checkin_questions SET label = 'I calculated my gross margin',               description = 'I calculated my gross margin — revenue minus input costs — for this season.'                        WHERE organisation_id = org_id AND crop_type = 'maize' AND week_number = 12 AND label ILIKE '%gross margin%';
